class SecureStorageService {
  // flutter_secure_storage uses Keychain on iOS and EncryptedSharedPreferences
  // (AES encryption backed by Android Keystore) on Android.
  final FlutterSecureStorage _secureStorage;

  // Keys for secure storage (tokens, sensitive credentials)
