      return AuthTokens(
        accessToken: accessToken,
        refreshToken: refreshToken,
        expiresAt: DateTime.parse(expiryString),
      );
    } catch (_) {
      await clearTokens();
      return null;
    }
  }

  Future<void> clearTokens() async {
    await _secureStorage.delete(key: _accessTokenKey);
    await _secureStorage.delete(key: _refreshTokenKey);
    await _secureStorage.delete(key: _tokenExpiryKey);
  }

  // ---------------------------------------------------------------------------
  // User Data Storage (Secure — contains PII like email)
  // ---------------------------------------------------------------------------

  Future<void> saveUserData(UserData userData) async {
    final jsonString = jsonEncode(userData.toJson());
    await _secureStorage.write(key: _userDataKey, value: jsonString);
  }

  Future<UserData?> loadUserData() async {
    final jsonString = await _secureStorage.read(key: _userDataKey);
    if (jsonString == null) return null;

    try {
      final json = jsonDecode(jsonString) as Map<String, dynamic>;
      return UserData.fromJson(json);
    } catch (_) {
      await _secureStorage.delete(key: _userDataKey);
      return null;
    }
  }

  Future<void> clearUserData() async {
    await _secureStorage.delete(key: _userDataKey);
  }

  // ---------------------------------------------------------------------------
  // Session Metadata (SharedPreferences — non-sensitive only)
  // ---------------------------------------------------------------------------

  Future<void> saveSessionMetadata({required String sessionId}) async {
    final prefs = await SharedPreferences.getInstance();
    await prefs.setBool(_isLoggedInKey, true);
    await prefs.setString(
        _lastLoginTimestampKey, DateTime.now().toIso8601String());
    await prefs.setString(_sessionIdKey, sessionId);
  }

  Future<bool> isLoggedIn() async {
    final prefs = await SharedPreferences.getInstance();
    return prefs.getBool(_isLoggedInKey) ?? false;
  }

  Future<String?> getSessionId() async {
    final prefs = await SharedPreferences.getInstance();
    return prefs.getString(_sessionIdKey);
  }

  Future<DateTime?> getLastLoginTimestamp() async {
    final prefs = await SharedPreferences.getInstance();
    final ts = prefs.getString(_lastLoginTimestampKey);
    return ts != null ? DateTime.tryParse(ts) : null;
  }

  Future<void> clearSessionMetadata() async {
    final prefs = await SharedPreferences.getInstance();
