class AuthManager extends ChangeNotifier {
  final SecureStorageService _storage;
  final AuthApiService _api;

  AuthState _state = const AuthState();
  AuthState get state => _state;

  AuthTokens? _tokens;

  AuthManager({
    SecureStorageService? storage,
    AuthApiService? api,
  })  : _storage = storage ?? SecureStorageService(),
        _api = api ?? AuthApiService();

  // ---------------------------------------------------------------------------
  // Initialize — restore session on app start
  // ---------------------------------------------------------------------------

  Future<void> initialize() async {
    _updateState(_state.copyWith(isLoading: true, clearError: true));

    try {
      final isLoggedIn = await _storage.isLoggedIn();
      if (!isLoggedIn) {
        _updateState(const AuthState());
        return;
      }

      final tokens = await _storage.loadTokens();
      final userData = await _storage.loadUserData();

      if (tokens == null || userData == null) {
        await _storage.clearAll();
        _updateState(const AuthState());
        return;
      }

      // If access token is expired, try to refresh
      if (tokens.isExpired) {
        final refreshed = await _tryRefreshTokens(tokens.refreshToken);
        if (!refreshed) {
          await _storage.clearAll();
          _updateState(const AuthState());
          return;
        }
      } else {
        _tokens = tokens;
      }

      _updateState(AuthState(
        isAuthenticated: true,
        user: userData,
      ));
    } catch (e) {
      await _storage.clearAll();
      _updateState(const AuthState());
    }
  }

  // ---------------------------------------------------------------------------
  // Login
  // ---------------------------------------------------------------------------

  Future<bool> login(String email, String password) async {
    _updateState(_state.copyWith(isLoading: true, clearError: true));

    try {
      final response = await _api.login(email, password);

      final tokens = AuthTokens(
        accessToken: response['accessToken'] as String,
        refreshToken: response['refreshToken'] as String,
        expiresAt: DateTime.now().add(
          Duration(seconds: response['expiresIn'] as int),
        ),
      );

      final userData = UserData.fromJson(
        response['user'] as Map<String, dynamic>,
      );

      final sessionId = response['sessionId'] as String;

      // Persist securely
      await _storage.saveTokens(tokens);
      await _storage.saveUserData(userData);
      await _storage.saveSessionMetadata(sessionId: sessionId);

      _tokens = tokens;

      _updateState(AuthState(
        isAuthenticated: true,
        user: userData,
      ));

      return true;
    } on AuthException catch (e) {
      _updateState(_state.copyWith(
        isLoading: false,
        errorMessage: e.message,
      ));
      return false;
    } catch (e) {
      _updateState(_state.copyWith(
        isLoading: false,
        errorMessage: 'An unexpected error occurred. Please try again.',
      ));
      return false;
    }
  }

  // ---------------------------------------------------------------------------
  // Logout
  // ---------------------------------------------------------------------------

  Future<void> logout() async {
    _updateState(_state.copyWith(isLoading: true));

    try {
      if (_tokens != null) {
        await _api.logout(_tokens!.accessToken);
      }
    } catch (_) {
      // Best-effort server logout; clear local state regardless
    }

    _tokens = null;
    await _storage.clearAll();
    _updateState(const AuthState());
  }

  // ---------------------------------------------------------------------------
  // Token Access (for HTTP interceptors)
  // ---------------------------------------------------------------------------

  Future<String?> getValidAccessToken() async {
    if (_tokens == null) return null;

    if (_tokens!.isExpired) {
      final refreshed = await _tryRefreshTokens(_tokens!.refreshToken);
      if (!refreshed) {
        await logout();
        return null;
      }
    }

    return _tokens!.accessToken;
  }

  // ---------------------------------------------------------------------------
  // Token Refresh
  // ---------------------------------------------------------------------------

  Future<bool> _tryRefreshTokens(String refreshToken) async {
    try {
      final response = await _api.refreshToken(refreshToken);

      final newTokens = AuthTokens(
        accessToken: response['accessToken'] as String,
        refreshToken: response['refreshToken'] as String,
        expiresAt: DateTime.now().add(
          Duration(seconds: response['expiresIn'] as int),
        ),
      );

      await _storage.saveTokens(newTokens);
      _tokens = newTokens;
      return true;
    } catch (_) {
      return false;
    }
  }

  // ---------------------------------------------------------------------------
  // Update User Data
  // ---------------------------------------------------------------------------

  Future<void> updateUserData(UserData updatedUser) async {
    await _storage.saveUserData(updatedUser);
    _updateState(_state.copyWith(user: updatedUser));
  }

  // ---------------------------------------------------------------------------
  // State Management
  // ---------------------------------------------------------------------------

  void _updateState(AuthState newState) {
    _state = newState;
    notifyListeners();
  }

  void clearError() {
    _updateState(_state.copyWith(clearError: true));
  }
}

